logging.basicConfig(level=logging.INFO)
logger = logging.getLogger("MMOServer")


class ItemRarity(str, Enum):
    COMMON = "common"
    UNCOMMON = "uncommon"
    RARE = "rare"
    EPIC = "epic"
    LEGENDARY = "legendary"


@dataclass
class Item:
    item_id: str
    name: str
    rarity: ItemRarity
    owner_id: Optional[str] = None
    tradeable: bool = True
    base_value: int = 0

    def to_dict(self):
        return {
            "item_id": self.item_id,
            "name": self.name,
            "rarity": self.rarity.value,
            "owner_id": self.owner_id,
            "tradeable": self.tradeable,
            "base_value": self.base_value,
        }


@dataclass
class TradeOffer:
    trade_id: str
    initiator_id: str
    target_id: str
    offered_items: List[str]  # item_ids from initiator
    requested_items: List[str]  # item_ids from target
    gold_offered: int = 0
    gold_requested: int = 0
    initiator_confirmed: bool = False
    target_confirmed: bool = False
    status: str = "pending"  # pending, accepted, declined, cancelled, completed
    created_at: float = field(default_factory=time.time)

    def to_dict(self):
        return {
            "trade_id": self.trade_id,
            "initiator_id": self.initiator_id,
            "target_id": self.target_id,
            "offered_items": self.offered_items,
            "requested_items": self.requested_items,
            "gold_offered": self.gold_offered,
            "gold_requested": self.gold_requested,
            "initiator_confirmed": self.initiator_confirmed,
            "target_confirmed": self.target_confirmed,
            "status": self.status,
        }


@dataclass
class Player:
    player_id: str
    username: str
    gold: int = 1000
    inventory: List[str] = field(default_factory=list)  # item_ids
    max_inventory_size: int = 50
    active_trade_id: Optional[str] = None
    online: bool = False

    def to_dict(self):
        return {
            "player_id": self.player_id,
            "username": self.username,
            "gold": self.gold,
            "inventory": self.inventory,
            "max_inventory_size": self.max_inventory_size,
            "active_trade_id": self.active_trade_id,
            "online": self.online,
        }


class InventoryManager:
    """Manages all items and inventory operations with concurrency safety."""

    def __init__(self):
        self.items: Dict[str, Item] = {}
        self._lock = asyncio.Lock()

    def create_item(self, name: str, rarity: ItemRarity, owner_id: str,
                    tradeable: bool = True, base_value: int = 0) -> Item:
        item_id = str(uuid.uuid4())[:8]
        item = Item(
            item_id=item_id,
            name=name,
            rarity=rarity,
            owner_id=owner_id,
            tradeable=tradeable,
            base_value=base_value,
        )
        self.items[item_id] = item
        return item

    async def transfer_item(self, item_id: str, from_player: Player,
                            to_player: Player) -> bool:
        async with self._lock:
            item = self.items.get(item_id)
            if not item:
                logger.warning(f"Item {item_id} not found")
                return False

            if item.owner_id != from_player.player_id:
                logger.warning(
                    f"Item {item_id} not owned by {from_player.username}")
                return False

            if not item.tradeable:
                logger.warning(f"Item {item_id} is not tradeable")
                return False

            if item_id not in from_player.inventory:
                logger.warning(
                    f"Item {item_id} not in {from_player.username}'s inventory")
                return False

            if len(to_player.inventory) >= to_player.max_inventory_size:
                logger.warning(
                    f"{to_player.username}'s inventory is full")
                return False

            from_player.inventory.remove(item_id)
            to_player.inventory.append(item_id)
            item.owner_id = to_player.player_id

            logger.info(
                f"Transferred {item.name} ({item_id}) from "
                f"{from_player.username} to {to_player.username}")
            return True

    async def transfer_gold(self, from_player: Player, to_player: Player,
                            amount: int) -> bool:
        async with self._lock:
            if amount < 0:
                return False
            if from_player.gold < amount:
                logger.warning(
                    f"{from_player.username} doesn't have enough gold "
                    f"({from_player.gold} < {amount})")
                return False

            from_player.gold -= amount
            to_player.gold += amount
            logger.info(
                f"Transferred {amount} gold from {from_player.username} "
                f"to {to_player.username}")
            return True

    def get_player_items(self, player: Player) -> List[Item]:
        return [self.items[iid] for iid in player.inventory
                if iid in self.items]


class TradeManager:
    """Manages trade sessions between players with concurrency safety."""

    def __init__(self, inventory_manager: InventoryManager):
        self.trades: Dict[str, TradeOffer] = {}
        self.inventory_manager = inventory_manager
        self._lock = asyncio.Lock()

    async def create_trade(self, initiator: Player, target: Player) -> Optional[TradeOffer]:
        async with self._lock:
            if initiator.active_trade_id:
                logger.warning(
                    f"{initiator.username} already in a trade")
                return None
            if target.active_trade_id:
                logger.warning(
                    f"{target.username} already in a trade")
                return None
            if initiator.player_id == target.player_id:
                logger.warning("Cannot trade with yourself")
                return None

            trade_id = str(uuid.uuid4())[:8]
            trade = TradeOffer(
                trade_id=trade_id,
                initiator_id=initiator.player_id,
                target_id=target.player_id,
                offered_items=[],
                requested_items=[],
            )
            self.trades[trade_id] = trade
            initiator.active_trade_id = trade_id
            target.active_trade_id = trade_id

            logger.info(
                f"Trade {trade_id} created between {initiator.username} "
                f"and {target.username}")
            return trade

    async def add_item_to_trade(self, trade_id: str, player_id: str,
                                item_id: str, players: Dict[str, Player]) -> bool:
        async with self._lock:
            trade = self.trades.get(trade_id)
            if not trade or trade.status != "pending":
                return False

            # Reset confirmations when trade contents change
            trade.initiator_confirmed = False
            trade.target_confirmed = False

            item = self.inventory_manager.items.get(item_id)
            if not item or item.owner_id != player_id or not item.tradeable:
                return False

            player = players.get(player_id)
            if not player or item_id not in player.inventory:
                return False

            if player_id == trade.initiator_id:
                if item_id not in trade.offered_items:
                    trade.offered_items.append(item_id)
            elif player_id == trade.target_id:
                if item_id not in trade.requested_items:
                    trade.requested_items.append(item_id)
            else:
                return False

            logger.info(
                f"Item {item_id} added to trade {trade_id} by {player.username}")
            return True

    async def remove_item_from_trade(self, trade_id: str, player_id: str,
                                     item_id: str) -> bool:
        async with self._lock:
            trade = self.trades.get(trade_id)
            if not trade or trade.status != "pending":
                return False

            trade.initiator_confirmed = False
            trade.target_confirmed = False

            if player_id == trade.initiator_id:
                if item_id in trade.offered_items:
                    trade.offered_items.remove(item_id)
                    return True
            elif player_id == trade.target_id:
                if item_id in trade.requested_items:
                    trade.requested_items.remove(item_id)
                    return True
            return False

    async def set_gold_offer(self, trade_id: str, player_id: str,
                             amount: int) -> bool:
        async with self._lock:
            trade = self.trades.get(trade_id)
            if not trade or trade.status != "pending" or amount < 0:
                return False

            trade.initiator_confirmed = False
            trade.target_confirmed = False

            if player_id == trade.initiator_id:
                trade.gold_offered = amount
            elif player_id == trade.target_id:
                trade.gold_requested = amount
            else:
                return False
            return True

    async def confirm_trade(self, trade_id: str, player_id: str,
                            players: Dict[str, Player]) -> Optional[str]:
        """Returns trade status after confirmation attempt."""
        async with self._lock:
            trade = self.trades.get(trade_id)
            if not trade or trade.status != "pending":
                return None

            if player_id == trade.initiator_id:
                trade.initiator_confirmed = True
            elif player_id == trade.target_id:
                trade.target_confirmed = True
            else:
                return None

            if trade.initiator_confirmed and trade.target_confirmed:
                # Both confirmed - execute the trade
                success = await self._execute_trade(trade, players)
                if success:
                    trade.status = "completed"
                    players[trade.initiator_id].active_trade_id = None
                    players[trade.target_id].active_trade_id = None
                    return "completed"
                else:
                    trade.status = "failed"
                    trade.initiator_confirmed = False
                    trade.target_confirmed = False
                    players[trade.initiator_id].active_trade_id = None
                    players[trade.target_id].active_trade_id = None
                    return "failed"

            return "confirmed"

    async def _execute_trade(self, trade: TradeOffer,
                             players: Dict[str, Player]) -> bool:
        """Execute the actual item and gold transfers. Lock must be held."""
        initiator = players.get(trade.initiator_id)
        target = players.get(trade.target_id)

        if not initiator or not target:
            return False

        # Validate all items still exist and are owned correctly
        for item_id in trade.offered_items:
            item = self.inventory_manager.items.get(item_id)
            if (not item or item.owner_id != initiator.player_id
                    or item_id not in initiator.inventory or not item.tradeable):
                logger.warning(
                    f"Trade validation failed: item {item_id} from initiator")
                return False

        for item_id in trade.requested_items:
            item = self.inventory_manager.items.get(item_id)
            if (not item or item.owner_id != target.player_id
                    or item_id not in target.inventory or not item.tradeable):
                logger.warning(
                    f"Trade validation failed: item {item_id} from target")
                return False

        # Validate gold
        if initiator.gold < trade.gold_offered:
            logger.warning("Initiator doesn't have enough gold")
            return False
        if target.gold < trade.gold_requested:
            logger.warning("Target doesn't have enough gold")
            return False

        # Validate inventory space
        initiator_net = (len(initiator.inventory)
                         - len(trade.offered_items)
                         + len(trade.requested_items))
        target_net = (len(target.inventory)
                      - len(trade.requested_items)
                      + len(trade.offered_items))

        if initiator_net > initiator.max_inventory_size:
            logger.warning("Initiator inventory would be full")
            return False
        if target_net > target.max_inventory_size:
            logger.warning("Target inventory would be full")
            return False

        # Execute transfers atomically (we hold the lock)
        # Transfer items from initiator to target
        for item_id in trade.offered_items:
            item = self.inventory_manager.items[item_id]
            initiator.inventory.remove(item_id)
            target.inventory.append(item_id)
            item.owner_id = target.player_id

        # Transfer items from target to initiator
        for item_id in trade.requested_items:
            item = self.inventory_manager.items[item_id]
            target.inventory.remove(item_id)
            initiator.inventory.append(item_id)
            item.owner_id = initiator.player_id

        # Transfer gold
        if trade.gold_offered > 0:
            initiator.gold -= trade.gold_offered
            target.gold += trade.gold_offered

        if trade.gold_requested > 0:
            target.gold -= trade.gold_requested
            initiator.gold += trade.gold_requested

        logger.info(f"Trade {trade.trade_id} completed successfully: "
                    f"{len(trade.offered_items)} items + {trade.gold_offered}g "
                    f"from {initiator.username}, "
                    f"{len(trade.requested_items)} items + {trade.gold_requested}g "
                    f"from {target.username}")
        return True

    async def cancel_trade(self, trade_id: str, player_id: str,
                           players: Dict[str, Player]) -> bool:
        async with self._lock:
            trade = self.trades.get(trade_id)
            if not trade or trade.status not in ("pending",):
                return False

            if player_id not in (trade.initiator_id, trade.target_id):
                return False

            trade.status = "cancelled"
            initiator = players.get(trade.initiator_id)
            target = players.get(trade.target_id)
            if initiator:
                initiator.active_trade_id = None
            if target:
                target.active_trade_id = None

            logger.info(f"Trade {trade_id} cancelled by {player_id}")
            return True

    async def decline_trade(self, trade_id: str, player_id: str,
                            players: Dict[str, Player]) -> bool:
        async with self._lock:
            trade = self.trades.get(trade_id)
            if not trade or trade.status != "pending":
                return False

            if player_id != trade.target_id:
                return False

            trade.status = "declined"
            initiator = players.get(trade.initiator_id)
            target = players.get(trade.target_id)
            if initiator:
                initiator.active_trade_id = None
            if target:
                target.active_trade_id = None

            logger.info(f"Trade {trade_id} declined by {player_id}")
            return True


class GameServer:
    """Main MMO game server handling websocket connections and game logic."""

    # Starter item templates
    STARTER_ITEMS = [
        ("Rusty Sword", ItemRarity.COMMON, 10),
        ("Wooden Shield", ItemRarity.COMMON, 8),
        ("Health Potion", ItemRarity.COMMON, 5),
        ("Leather Armor", ItemRarity.UNCOMMON, 25),
        ("Magic Ring", ItemRarity.RARE, 100),
    ]

    def __init__(self, host: str = "localhost", port: int = 8765):
        self.host = host
        self.port = port
        self.players: Dict[str, Player] = {}
        self.connections: Dict[str, websockets.WebSocketServerProtocol] = {}
        # Map websocket to player_id
        self.ws_to_player: Dict[websockets.WebSocketServerProtocol, str] = {}
        self.inventory_manager = InventoryManager()
        self.trade_manager = TradeManager(self.inventory_manager)
        self._connection_lock = asyncio.Lock()

    def _create_starter_inventory(self, player: Player):
        """Give a new player some starter items."""
        for name, rarity, value in self.STARTER_ITEMS:
            item = self.inventory_manager.create_item(
                name=name,
                rarity=rarity,
                owner_id=player.player_id,
                base_value=value,
            )
            player.inventory.append(item.item_id)

    async def _send(self, player_id: str, message: dict):
        ws = self.connections.get(player_id)
        if ws:
            try:
                await ws.send(json.dumps(message))
            except websockets.exceptions.ConnectionClosed:
                logger.warning(
                    f"Failed to send to {player_id}: connection closed")

    async def _broadcast(self, message: dict, exclude: Optional[Set[str]] = None):
        exclude = exclude or set()
        tasks = []
        for pid, ws in self.connections.items():
            if pid not in exclude:
                tasks.append(self._send(pid, message))
        if tasks:
            await asyncio.gather(*tasks)

    async def _send_error(self, player_id: str, error: str):
        await self._send(player_id, {
            "type": "error",
            "message": error,
        })

    async def handle_login(self, websocket, data: dict):
        username = data.get("username", "").strip()
        if not username:
            await websocket.send(json.dumps({
                "type": "error",
                "message": "Username required",
            }))
            return None

        async with self._connection_lock:
            # Check if username already logged in
            for pid, player in self.players.items():
                if player.username == username and player.online:
                    await websocket.send(json.dumps({
                        "type": "error",
                        "message": "Username already logged in",
                    }))
                    return None

            # Find existing player or create new one
            existing_player = None
            for pid, player in self.players.items():
                if player.username == username:
                    existing_player = player
                    break

            if existing_player:
                player = existing_player
                player.online = True
            else:
                player_id = str(uuid.uuid4())[:8]
                player = Player(
                    player_id=player_id,
                    username=username,
                    online=True,
                )
                self._create_starter_inventory(player)
                self.players[player_id] = player

            self.connections[player.player_id] = websocket
            self.ws_to_player[websocket] = player.player_id

        logger.info(f"Player {player.username} ({player.player_id}) logged in")

        # Send login success
        items_data = [item.to_dict() for item in
                      self.inventory_manager.get_player_items(player)]
        await self._send(player.player_id, {
            "type": "login_success",
            "player": player.to_dict(),
            "items": items_data,
        })

        # Notify others
        online_players = [
            {"player_id": p.player_id, "username": p.username}
            for p in self.players.values()
            if p.online and p.player_id != player.player_id
        ]
        await self._send(player.player_id, {
            "type": "online_players",
            "players": online_players,
        })

        await self._broadcast({
            "type": "player_joined",
            "player_id": player.player_id,
            "username": player.username,
        }, exclude={player.player_id})

        return player.player_id

    async def handle_disconnect(self, websocket):
        async with self._connection_lock:
            player_id = self.ws_to_player.pop(websocket, None)
            if player_id:
                self.connections.pop(player_id, None)
                player = self.players.get(player_id)
                if player:
                    player.online = False

                    # Cancel any active trade
                    if player.active_trade_id:
                        trade = self.trade_manager.trades.get(
                            player.active_trade_id)
                        if trade and trade.status == "pending":
                            await self.trade_manager.cancel_trade(
                                trade.trade_id, player_id, self.players)
                            # Notify the other party
                            other_id = (trade.target_id
                                        if trade.initiator_id == player_id
                                        else trade.initiator_id)
                            await self._send(other_id, {
                                "type": "trade_cancelled",
                                "trade_id": trade.trade_id,
                                "reason": f"{player.username} disconnected",
                            })

                    logger.info(
                        f"Player {player.username} ({player_id}) disconnected")
                    await self._broadcast({
                        "type": "player_left",
                        "player_id": player_id,
                        "username": player.username,
                    })

    async def handle_get_inventory(self, player_id: str, data: dict):
        player = self.players.get(player_id)
        if not player:
            return

        items_data = [item.to_dict() for item in
                      self.inventory_manager.get_player_items(player)]
        await self._send(player_id, {
            "type": "inventory",
            "player_id": player_id,
            "gold": player.gold,
            "items": items_data,
        })

    async def handle_inspect_player(self, player_id: str, data: dict):
        target_id = data.get("target_id")
        target = self.players.get(target_id)
        if not target:
            await self._send_error(player_id, "Player not found")
            return

        items_data = [item.to_dict() for item in
                      self.inventory_manager.get_player_items(target)]
        await self._send(player_id, {
            "type": "player_info",
            "player_id": target.player_id,
            "username": target.username,
            "items": items_data,
            "online": target.online,
        })

    async def handle_trade_request(self, player_id: str, data: dict):
        target_id = data.get("target_id")
        initiator = self.players.get(player_id)
        target = self.players.get(target_id)

        if not initiator or not target:
            await self._send_error(player_id, "Player not found")
            return

        if not target.online:
            await self._send_error(player_id, "Player is offline")
            return

        trade = await self.trade_manager.create_trade(initiator, target)
        if not trade:
            await self._send_error(
                player_id,
                "Cannot create trade. One of the players may already be trading.")
            return

        await self._send(player_id, {
            "type": "trade_created",
            "trade": trade.to_dict(),
            "role": "initiator",
        })

        await self._send(target_id, {
            "type": "trade_request",
            "trade": trade.to_dict(),
            "from_player": initiator.username,
            "role": "target",
        })

    async def handle_trade_add_item(self, player_id: str, data: dict):
        trade_id = data.get("trade_id")
        item_id = data.get("item_id")

        if not trade_id or not item_id:
            await self._send_error(player_id, "trade_id and item_id required")
            return

        success = await self.trade_manager.add_item_to_trade(
            trade_id, player_id, item_id, self.players)

        if not success:
            await self._send_error(player_id, "Cannot add item to trade")
            return

        trade = self.trade_manager.trades[trade_id]
        trade_data = trade.to_dict()

        # Notify both parties
        await self._send(trade.initiator_id, {
            "type": "trade_updated",
            "trade": trade_data,
        })
        await self._send(trade.target_id, {
            "type": "trade_updated",
            "trade": trade_data,
        })

    async def handle_trade_remove_item(self, player_id: str, data: dict):
        trade_id = data.get("trade_id")
        item_id = data.get("item_id")

        if not trade_id or not item_id:
            await self._send_error(player_id, "trade_id and item_id required")
            return

        success = await self.trade_manager.remove_item_from_trade(
            trade_id, player_id, item_id)

        if not success:
            await self._send_error(player_id, "Cannot remove item from trade")
            return

        trade = self.trade_manager.trades[trade_id]
        trade_data = trade.to_dict()

        await self._send(trade.initiator_id, {
            "type": "trade_updated",
            "trade": trade_data,
        })
        await self._send(trade.target_id, {
            "type": "trade_updated",
            "trade": trade_data,
        })

    async def handle_trade_set_gold(self, player_id: str, data: dict):
        trade_id = data.get("trade_id")
        amount = data.get("amount", 0)

        if not trade_id:
            await self._send_error(player_id, "trade_id required")
            return

        if not isinstance(amount, int) or amount < 0:
            await self._send_error(player_id, "Invalid gold amount")
            return

        success = await self.trade_manager.set_gold_offer(
            trade_id, player_id, amount)

        if not success:
            await self._send_error(player_id, "Cannot set gold amount")
            return

        trade = self.trade_manager.trades[trade_id]
        trade_data = trade.to_dict()

        await self._send(trade.initiator_id, {
            "type": "trade_updated",
            "trade": trade_data,
        })
        await self._send(trade.target_id, {
            "type": "trade_updated",
            "trade": trade_data,
        })

    async def handle_trade_confirm(self, player_id: str, data: dict):
        trade_id = data.get("trade_id")

        if not trade_id:
            await self._send_error(player_id, "trade_id required")
            return

        result = await self.trade_manager.confirm_trade(
            trade_id, player_id, self.players)

        if not result:
            await self._send_error(player_id, "Cannot confirm trade")
            return

        trade = self.trade_manager.trades[trade_id]

        if result == "confirmed":
            # One party confirmed, notify both
            await self._send(trade.initiator_id, {
                "type": "trade_updated",
                "trade": trade.to_dict(),
                "message": f"{'Initiator' if player_id == trade.initiator_id else 'Target'} confirmed",
            })
            await self._send(trade.target_id, {
                "type": "trade_updated",
                "trade": trade.to_dict(),
                "message": f"{'Initiator' if player_id == trade.initiator_id else 'Target'} confirmed",
            })

        elif result == "completed":
            initiator = self.players[trade.initiator_id]
            target = self.players[trade.target_id]

            initiator_items = [item.to_dict() for item in
                               self.inventory_manager.get_player_items(initiator)]
            target_items = [item.to_dict() for item in
                            self.inventory_manager.get_player_items(target)]

            await self._send(trade.initiator_id, {
                "type": "trade_completed",
                "trade": trade.to_dict(),
                "your_inventory": initiator_items,
                "your_gold": initiator.gold,
            })
            await self._send(trade.target_id, {
                "type": "trade_completed",
                "trade": trade.to_dict(),
                "your_inventory": target_items,
                "your_gold": target.gold,
            })

        elif result == "failed":
            await self._send(trade.initiator_id, {
                "type": "trade_failed",
                "trade_id": trade_id,
                "reason": "Trade validation failed. Items may have changed.",
            })
            await self._send(trade.target_id, {
                "type": "trade_failed",
                "trade_id": trade_id,
                "reason": "Trade validation failed. Items may have changed.",
            })

    async def handle_trade_cancel(self, player_id: str, data: dict):
        trade_id = data.get("trade_id")

        if not trade_id:
            await self._send_error(player_id, "trade_id required")
            return

        trade = self.trade_manager.trades.get(trade_id)
        if not trade:
            await self._send_error(player_id, "Trade not found")
            return

        success = await self.trade_manager.cancel_trade(
            trade_id, player_id, self.players)

        if not success:
            await self._send_error(player_id, "Cannot cancel trade")
            return

        player = self.players[player_id]
        await self._send(trade.initiator_id, {
            "type": "trade_cancelled",
            "trade_id": trade_id,
            "reason": f"{player.username} cancelled the trade",
        })
        await self._send(trade.target_id, {
            "type": "trade_cancelled",
            "trade_id": trade_id,
            "reason": f"{player.username} cancelled the trade",
        })

    async def handle_trade_decline(self, player_id: str, data: dict):
        trade_id = data.get("trade_id")

        if not trade_id:
            await self._send_error(player_id, "trade_id required")
            return

        trade = self.trade_manager.trades.get(trade_id)
        if not trade:
            await self._send_error(player_id, "Trade not found")
            return

        success = await self.trade_manager.decline_trade(
            trade_id, player_id, self.players)

        if not success:
            await self._send_error(player_id, "Cannot decline trade")
            return

        player = self.players[player_id]
        await self._send(trade.initiator_id, {
            "type": "trade_declined",
            "trade_id": trade_id,
            "reason": f"{player.username} declined the trade",
        })
        await self._send(trade.target_id, {
            "type": "trade_declined",
            "trade_id": trade_id,
            "reason": "You declined the trade",
        })

    async def handle_direct_transfer(self, player_id: str, data: dict):
        """Handle a direct item gift/transfer outside of the trade window."""
        target_id = data.get("target_id")
        item_id = data.get("item_id")

        from_player = self.players.get(player_id)
        to_player = self.players.get(target_id)

        if not from_player or not to_player:
            await self._send_error(player_id, "Player not found")
            return

        if not to_player.online:
            await self._send_error(player_id, "Target player is offline")
            return

        success = await self.inventory_manager.transfer_item(
            item_id, from_player, to_player)

        if not success:
            await self._send_error(player_id, "Transfer failed")
            return

        item = self.inventory_manager.items[item_id]

        await self._send(player_id, {
            "type": "item_sent",
            "item": item.to_dict(),
            "to_player": to_player.username,
        })

        await self._send(target_id, {
            "type": "item_received",
            "item": item.to_dict(),
            "from_player": from_player.username,
        })

    async def handle_drop_item(self, player_id: str, data: dict):
        """Handle dropping/destroying an item."""
        item_id = data.get("item_id")
        player = self.players.get(player_id)

        if not player or not item_id:
            await self._send_error(player_id, "Invalid request")
            return

        async with self.inventory_manager._lock:
            item = self.inventory_manager.items.get(item_id)
            if not item or item.owner_id != player_id:
                await self._send_error(player_id, "Item not found or not owned")
                return

            if item_id in player.inventory:
                player.inventory.remove(item_id)
                item.owner_id = None
                del self.inventory_manager.items[item_id]

        await self._send(player_id, {
            "type": "item_dropped",
            "item_id": item_id,
            "message": f"Dropped {item.name}",
        })

    # Message handler dispatcher
    MESSAGE_HANDLERS = {
        "get_inventory": "handle_get_inventory",
        "inspect_player": "handle_inspect_player",
        "trade_request": "handle_trade_request",
        "trade_add_item": "handle_trade_add_item",
        "trade_remove_item": "handle_trade_remove_item",
        "trade_set_gold": "handle_trade_set_gold",
        "trade_confirm": "handle_trade_confirm",
        "trade_cancel": "handle_trade_cancel",
        "trade_decline": "handle_trade_decline",
        "direct_transfer": "handle_direct_transfer",
        "drop_item": "handle_drop_item",
    }

    async def handle_message(self, player_id: str, websocket, raw_message: str):
        try:
            data = json.loads(raw_message)
        except json.JSONDecodeError:
            await self._send_error(player_id, "Invalid JSON")
            return

        msg_type = data.get("type")
        if not msg_type:
            await self._send_error(player_id, "Message type required")
            return

        handler_name = self.MESSAGE_HANDLERS.get(msg_type)
        if handler_name:
            handler = getattr(self, handler_name)
            await handler(player_id, data)
        else:
            await self._send_error(player_id, f"Unknown message type: {msg_type}")

    async def handle_connection(self, websocket, path=None):
        player_id = None
        try:
            # Wait for login message
            raw = await asyncio.wait_for(websocket.recv(), timeout=30.0)
            data = json.loads(raw)

            if data.get("type") != "login":
                await websocket.send(json.dumps({
                    "type": "error",
                    "message": "First message must be login",
                }))
                return

            player_id = await self.handle_login(websocket, data)
            if not player_id:
                return

            # Main message loop
            async for message in websocket:
                await self.handle_message(player_id, websocket, message)

        except asyncio.TimeoutError:
            logger.info("Connection timed out waiting for login")
        except websockets.exceptions.ConnectionClosed as e:
            logger.info(f"Connection closed: {e}")
        except Exception as e:
            logger.error(f"Error handling connection: {e}", exc_info=True)
        finally:
            await self.handle_disconnect(websocket)

    async def cleanup_stale_trades(self):
        """Periodic task to clean up old/stale trades."""
        while True:
            await asyncio.sleep(60)
            now = time.time()
            stale_trade_ids = []

            for trade_id, trade in self.trade_manager.trades.items():
                if trade.status == "pending" and (now - trade.created_at) > 300:
                    stale_trade_ids.append(trade_id)

            for trade_id in stale_trade_ids:
                trade = self.trade_manager.trades.get(trade_id)
                if trade and trade.status == "pending":
                    async with self.trade_manager._lock:
                        trade.status = "cancelled"
                        initiator = self.players.get(trade.initiator_id)
                        target = self.players.get(trade.target_id)
                        if initiator:
                            initiator.active_trade_id = None
                        if target:
                            target.active_trade_id = None

                    await self._send(trade.initiator_id, {
                        "type": "trade_cancelled",
                        "trade_id": trade_id,
                        "reason": "Trade expired (5 minute timeout)",
                    })
                    await self._send(trade.target_id, {
                        "type": "trade_cancelled",
                        "trade_id": trade_id,
                        "reason": "Trade expired (5 minute timeout)",
                    })
                    logger.info(f"Stale trade {trade_id} cleaned up")

    async def start(self):
        logger.info(f"Starting MMO Game Server on {self.host}:{self.port}")

        # Start background tasks
        cleanup_task = asyncio.create_task(self.cleanup_stale_trades())

        try:
            async with websockets.serve(
                self.handle_connection,
                self.host,
                self.port,
                ping_interval=20,
                ping_timeout=20,
            ):
                logger.info(f"Server is running on ws://{self.host}:{self.port}")
                await asyncio.Future()  # Run forever
        finally:
            cleanup_task.cancel()


# --- Simple test client for demonstration ---
async def test_client(username: str, actions: list):
    """A simple test client to demonstrate server interaction."""
    uri = "ws://localhost:8765"
    async with websockets.connect(uri) as ws:
        # Login
        await ws.send(json.dumps({"type": "login", "username": username}))
        response = json.loads(await ws.recv())
        print(f"[{username}] {response['type']}: "
              f"{json.dumps(response, indent=2)[:200]}")

        # Consume online_players message
        try:
            response = json.loads(
                await asyncio.wait_for(ws.recv(), timeout=1.0))
            print(f"[{username}] {response['type']}")
        except asyncio.TimeoutError:
            pass

        # Drain any player_joined notifications
        while True:
            try:
                msg = json.loads(
                    await asyncio.wait_for(ws.recv(), timeout=0.5))
                print(f"[{username}] notification: {msg['type']}")
            except asyncio.TimeoutError:
                break

        for action in actions:
            await ws.send(json.dumps(action))
            # Read responses
            try:
                while True:
                    msg = json.loads(
                        await asyncio.wait_for(ws.recv(), timeout=2.0))
                    print(f"[{username}] {msg['type']}: "
                          f"{json.dumps(msg, indent=2)[:300]}")
            except asyncio.TimeoutError:
                pass

        return ws


async def run_demo():
    """Run a demo showing two players trading."""
    server = GameServer()
    server_task = asyncio.create_task(server.start())
    await asyncio.sleep(1)

    try:
        # Connect two players
        uri = "ws://localhost:8765"

        async with websockets.connect(uri) as ws1, \
                websockets.connect(uri) as ws2:

            # Login player 1
            await ws1.send(json.dumps({"type": "login", "username": "Alice"}))
            r1 = json.loads(await ws1.recv())
            alice_id = r1["player"]["player_id"]
            alice_items = r1["items"]
            print(f"Alice logged in: {alice_id}")
            print(f"Alice's items: {[i['name'] for i in alice_items]}")

            # Drain notifications for ws1
            try:
                while True:
                    await asyncio.wait_for(ws1.recv(), timeout=0.3)
            except asyncio.TimeoutError:
                pass

            # Login player 2
            await ws2.send(json.dumps({"type": "login", "username": "Bob"}))
            r2 = json.loads(await ws2.recv())
            bob_id = r2["player"]["player_id"]
            bob_items = r2["items"]
            print(f"\nBob logged in: {bob_id}")
            print(f"Bob's items: {[i['name'] for i in bob_items]}")

            # Drain notifications
            for ws in [ws1, ws2]:
                try:
                    while True:
                        await asyncio.wait_for(ws.recv(), timeout=0.3)
                except asyncio.TimeoutError:
                    pass

            # Alice initiates trade with Bob
            print("\n--- Alice initiates trade with Bob ---")
            await ws1.send(json.dumps({
                "type": "trade_request",
                "target_id": bob_id,
            }))

            # Alice receives trade_created
            r = json.loads(await ws1.recv())
            trade_id = r["trade"]["trade_id"]
            print(f"Trade created: {trade_id}")

            # Bob receives trade_request
            r = json.loads(await ws2.recv())
            print(f"Bob received trade request from {r['from_player']}")

            # Alice adds her Magic Ring to the trade
            magic_ring_id = alice_items[4]["item_id"]  # Magic Ring
            print(f"\n--- Alice offers Magic Ring ({magic_ring_id}) ---")
            await ws1.send(json.dumps({
                "type": "trade_add_item",
                "trade_id": trade_id,
                "item_id": magic_ring_id,
            }))

            # Both receive trade_updated
            for ws, name in [(ws1, "Alice"), (ws2, "Bob")]:
                r = json.loads(await ws.recv())
                print(f"{name} sees trade update: "
                      f"offered={r['trade']['offered_items']}")

            # Alice offers 200 gold
            print("\n--- Alice offers 200 gold ---")
            await ws1.send(json.dumps({
                "type": "trade_set_gold",
                "trade_id": trade_id,
                "amount": 200,
            }))

            for ws, name in [(ws1, "Alice"), (ws2, "Bob")]:
                r = json.loads(await ws.recv())
                print(f"{name} sees gold update: "
                      f"offered_gold={r['trade']['gold_offered']}")

            # Bob adds his Leather Armor
            leather_id = bob_items[3]["item_id"]  # Leather Armor
            print(f"\n--- Bob offers Leather Armor ({leather_id}) ---")
            await ws2.send(json.dumps({
                "type": "trade_add_item",
                "trade_id": trade_id,
                "item_id": leather_id,
            }))

            for ws, name in [(ws1, "Alice"), (ws2, "Bob")]:
                r = json.loads(await ws.recv())
                print(f"{name} sees trade update: "
                      f"requested={r['trade']['requested_items']}")

            # Alice confirms
            print("\n--- Alice confirms trade ---")
            await ws1.send(json.dumps({
                "type": "trade_confirm",
                "trade_id": trade_id,
            }))

            for ws, name in [(ws1, "Alice"), (ws2, "Bob")]:
                r = json.loads(await ws.recv())
                print(f"{name}: {r['type']} - "
                      f"initiator_confirmed={r['trade']['initiator_confirmed']}")

            # Bob confirms - trade should complete
            print("\n--- Bob confirms trade ---")
            await ws2.send(json.dumps({
                "type": "trade_confirm",
                "trade_id": trade_id,
            }))

            for ws, name in [(ws1, "Alice"), (ws2, "Bob")]:
                r = json.loads(await ws.recv())
                print(f"{name}: {r['type']}")
                if r["type"] == "trade_completed":
                    print(f"  Gold: {r['your_gold']}")
                    print(f"  Items: {[i['name'] for i in r['your_inventory']]}")

            print("\n--- Trade completed successfully! ---")

    except Exception as e:
        print(f"Demo error: {e}")
        import traceback
        traceback.print_exc()
    finally:
        server_task.cancel()
        try:
            await server_task
        except asyncio.CancelledError:
            pass


if __name__ == "__main__":
    import sys

    if len(sys.argv) > 1 and sys.argv[1] == "demo":
        asyncio.run(run_demo())
    else:
        server = GameServer()
        asyncio.run(server.start())